# Basic Logic Gates Implementation
# Truth Tables for Fundamental Gates

def AND(a, b):
    return a and b

def OR(a, b):
    return a or b

def NOT(a):
    return not a

def NAND(a, b):
    return not (a and b)

def NOR(a, b):
    return not (a or b)

def XOR(a, b):
    return (a and not b) or (not a and b)

# Print Truth Tables
print("=" * 50)
print("AND Gate Truth Table")
print("A | B | Output")
print("-" * 10)
for a in [False, True]:
    for b in [False, True]:
        print(f"{int(a)} | {int(b)} | {int(AND(a, b))}")

print("\n" + "=" * 50)
print("OR Gate Truth Table")
print("A | B | Output")
print("-" * 10)
for a in [False, True]:
    for b in [False, True]:
        print(f"{int(a)} | {int(b)} | {int(OR(a, b))}")

print("\n" + "=" * 50)
print("XOR Gate Truth Table")
print("A | B | Output")
print("-" * 10)
for a in [False, True]:
    for b in [False, True]:
        print(f"{int(a)} | {int(b)} | {int(XOR(a, b))}")
